/**
 * @summary List pattern observations and suggestions
 */
export const getListPatternsUrl = (params?: ListPatternsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/patterns?${stringifiedParams}`
    : `/api/patterns`;
};

export const listPatterns = async (
  params?: ListPatternsParams,
  options?: RequestInit,
): Promise<PatternObservation[]> => {
  return customFetch<PatternObservation[]>(getListPatternsUrl(params), {
    ...options,
    method: "GET",
  });
};

